/**
 * Updates an existing spreadsheet to implement the modular admin design
 */
function updateMasterAdminSpreadsheet() {
  const ss = SpreadsheetApp.getActive();

  // Create or update required sheets
  createOrUpdateUsersSheet(ss);
  createOrUpdateShopPartnersSheet(ss);
  createOrUpdateProjectLeadsSheet(ss);
  createOrUpdateIndustriesSheet(ss);
  createOrUpdateProjectStatusSheet(ss);
  createOrUpdateValidationsSheet(ss);
  createOrUpdateLogsSheet(ss);
  createOrUpdateSettingsSheet(ss);

  // Add spreadsheet protection
  protectAdminSheets(ss);

  // Create triggers for logging
  setupTriggers();
}

/**
 * Creates or updates the Users sheet
 */
function createOrUpdateUsersSheet(ss) {
  let sheet = ss.getSheetByName('Users');
  if (!sheet) {
    sheet = ss.insertSheet('Users');
  }

  // Set headers
  const headers = ['UserID', 'Name', 'Email', 'Role', 'IsActive', 'LastLogin', 'Notes'];
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  // Add data validation for Role
  const roleRange = sheet.getRange(2, 4, 999, 1);
  const roleRule = SpreadsheetApp.newDataValidation()
    .requireValueInList(['Admin', 'Editor', 'Viewer'])
    .build();
  roleRange.setDataValidation(roleRule);

  // Add checkbox for IsActive
  const activeRange = sheet.getRange(2, 5, 999, 1);
  const activeRule = SpreadsheetApp.newDataValidation()
    .requireCheckbox()
    .build();
  activeRange.setDataValidation(activeRule);

  formatSheet(sheet);
}

